<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use App\Http\Requests\Admin\UpdateHomepageSectionRequest; use App\Models\HomepageSection; use App\Services\FileUploadService; use Illuminate\Http\RedirectResponse; use Illuminate\Support\Facades\Cache; use Illuminate\View\View;
class HomepageSectionController extends Controller { public const LABELS=['about'=>'About / Who We Are Section','project_highlights'=>'Project Highlights Section','gallery_cta'=>'Gallery CTA Strip','services'=>'What We Do / Services Section']; public function index(): View { $this->ensureRequiredSections(); $items=HomepageSection::query()->whereIn('section_key',array_keys(self::LABELS))->ordered()->get(); return view('admin.pages.homepage-sections.index',['items'=>$items,'labels'=>self::LABELS]); } public function edit(HomepageSection $homepageSection): View { abort_unless(array_key_exists($homepageSection->section_key,self::LABELS),404); return view('admin.pages.homepage-sections.form',['item'=>$homepageSection,'label'=>self::LABELS[$homepageSection->section_key]]); } public function update(UpdateHomepageSectionRequest $request, HomepageSection $homepageSection, FileUploadService $uploader): RedirectResponse { abort_unless(array_key_exists($homepageSection->section_key,self::LABELS),404); $data=$request->validated(); $data['status']=(bool)($data['status']??false); $data['sort_order']=(int)($data['sort_order']??0); $data['image']=$uploader->replace($request->file('image'),$homepageSection->image,'uploads/homepage-sections'); $data['background_image']=$uploader->replace($request->file('background_image'),$homepageSection->background_image,'uploads/homepage-sections/backgrounds'); $homepageSection->update($data); $this->clearCache($homepageSection->section_key); return redirect()->route('admin.homepage-sections.index')->with('success','Homepage section updated successfully.'); } private function ensureRequiredSections(): void { foreach (self::LABELS as $key=>$label) { HomepageSection::firstOrCreate(['section_key'=>$key],['title'=>$label,'status'=>true,'sort_order'=>0]); } } private function clearCache(string $key): void { Cache::forget('homepage_sections'); Cache::forget('homepage_section_'.$key); } }
